(1, 1, '2026-03-29 21:19:02', '2026-03-29 21:19:02', '<!-- wp:paragraph -->\n<p>Welcome to WordPress. This is your first post. Edit or delete it, then start writing!</p>\n<!-- /wp:paragraph -->', 'Hello world!', '', 'publish', 'open', 'open', '', 'hello-world', '', '', '2026-03-29 21:19:02', '2026-03-29 21:19:02', '', 0, 'http://localhost/bookshop/?p=1', 0, 'post', '', 1),
(2, 1, '2026-03-29 21:19:02', '2026-03-29 21:19:02', '<!-- wp:paragraph -->\n<p>This is an example page. It\'s different from a blog post because it will stay in one place and will show up in your site navigation (in most themes). Most people start with an About page that introduces them to potential site visitors. It might say something like this:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:quote -->\n<blockquote class=\"wp-block-quote\">\n<!-- wp:paragraph -->\n<p>Hi there! I\'m a bike messenger by day, aspiring actor by night, and this is my website. I live in Los Angeles, have a great dog named Jack, and I like pi&#241;a coladas. (And gettin\' caught in the rain.)</p>\n<!-- /wp:paragraph -->\n</blockquote>\n<!-- /wp:quote -->\n\n<!-- wp:paragraph -->\n<p>...or something like this:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:quote -->\n<blockquote class=\"wp-block-quote\">\n<!-- wp:paragraph -->\n<p>The XYZ Doohickey Company was founded in 1971, and has been providing quality doohickeys to the public ever since. Located in Gotham City, XYZ employs over 2,000 people and does all kinds of awesome things for the Gotham community.</p>\n<!-- /wp:paragraph -->\n</blockquote>\n<!-- /wp:quote -->\n\n<!-- wp:paragraph -->\n<p>As a new WordPress user, you should go to <a href=\"http://localhost/bookshop/wp-admin/\">your dashboard</a> to delete this page and create new pages for your content. Have fun!</p>\n<!-- /wp:paragraph -->', 'Sample Page', '', 'trash', 'closed', 'open', '', 'sample-page__trashed', '', '', '2026-03-30 00:58:09', '2026-03-30 00:58:09', '', 0, 'http://localhost/bookshop/?page_id=2', 0, 'page', '', 0),
(3, 1, '2026-03-29 21:19:02', '2026-03-29 21:19:02', '<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">At Kabarak Bookshop, we value your privacy and are committed to protecting your personal information. This Privacy Policy outlines how we collect, use, and safeguard your data when you use our website.</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Information We Collect<br></strong>We may collect personal information such as your name, email address, phone number, and delivery details when you place an order or create an account on our platform.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>How We Use Your Information<br></strong>The information collected is used to process orders, manage user accounts, and improve the overall functionality of the website. We may also use your contact details to communicate order updates or important information related to your purchases.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Data Protection</strong><br>We take appropriate measures to ensure that your personal information is stored securely and protected against unauthorized access.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Sharing of Information</strong><br>We do not sell, trade, or share your personal information with third parties, except where necessary to complete your order or comply with legal requirements.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Cookies</strong><br>This website may use cookies to enhance user experience and improve site performance.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Changes to This Policy</strong><br>Kabarak Bookshop reserves the right to update this Privacy Policy at any time. Any changes will be reflected on this page.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Contact Us</strong><br>If you have any questions regarding this Privacy Policy, please contact us through the website.</p>\n<!-- /wp:paragraph -->', 'Privacy Policy', '', 'publish', 'closed', 'open', '', 'privacy-policy', '', '', '2026-03-30 01:12:52', '2026-03-30 01:12:52', '', 0, 'http://localhost/bookshop/?page_id=3', 0, 'page', '', 0),
