(9, 1, '2026-03-29 21:39:26', '2026-03-29 21:39:26', '<!-- wp:woocommerce/product-collection {\"queryId\":9,\"query\":{\"perPage\":9,\"pages\":0,\"offset\":0,\"postType\":\"product\",\"order\":\"asc\",\"orderBy\":\"title\",\"search\":\"\",\"exclude\":[],\"inherit\":false,\"taxQuery\":[],\"isProductCollectionBlock\":true,\"featured\":false,\"woocommerceOnSale\":false,\"woocommerceStockStatus\":[\"instock\",\"outofstock\",\"onbackorder\"],\"woocommerceAttributes\":[],\"woocommerceHandPickedProducts\":[],\"filterable\":false,\"relatedBy\":{\"categories\":true,\"tags\":true}},\"tagName\":\"div\",\"displayLayout\":{\"type\":\"flex\",\"columns\":3,\"shrinkColumns\":true},\"dimensions\":{\"widthType\":\"fill\"},\"queryContextIncludes\":[\"collection\"],\"__privatePreviewState\":{\"isPreview\":false,\"previewMessage\":\"Actual products will vary depending on the page being viewed.\"}} -->\n<div class=\"wp-block-woocommerce-product-collection\"><!-- wp:woocommerce/single-product {\"productId\":15} -->\n<div class=\"wp-block-woocommerce-single-product woocommerce\"><!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:woocommerce/product-gallery -->\n<div class=\"wp-block-woocommerce-product-gallery wc-block-product-gallery\"><!-- wp:woocommerce/product-gallery-thumbnails /-->\n\n<!-- wp:woocommerce/product-gallery-large-image -->\n<div class=\"wp-block-woocommerce-product-gallery-large-image wc-block-product-gallery-large-image__inner-blocks\"><!-- wp:woocommerce/product-image {\"showProductLink\":false,\"showSaleBadge\":false,\"isDescendentOfQueryLoop\":true,\"isDescendentOfSingleProductBlock\":true} /-->\n\n<!-- wp:woocommerce/product-sale-badge {\"align\":\"right\"} /-->\n\n<!-- wp:woocommerce/product-gallery-large-image-next-previous -->\n<div class=\"wp-block-woocommerce-product-gallery-large-image-next-previous\"></div>\n<!-- /wp:woocommerce/product-gallery-large-image-next-previous --></div>\n<!-- /wp:woocommer