(13, 1, '2026-03-30 01:12:24', '0000-00-00 00:00:00', '<!-- wp:paragraph -->\n<p><b><em>This is a sample page.</em></b></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">At Kabarak Bookshop, we aim to ensure customer satisfaction with every purchase. This Refund and Return Policy outlines the conditions under which returns and refunds are accepted.</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Returns</strong><br>Customers may request a return within 3–5 days of receiving their order if the item is damaged, defective, or incorrect. The item must be in its original condition and packaging.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Refunds</strong><br>Once a returned item is received and inspected, a refund will be processed. Refunds are issued based on the original method of payment or as agreed upon with the customer.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Non-Returnable Items</strong><br>Books that have been used, damaged by the customer, or altered in any way may not be eligible for return.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Order Issues</strong><br>If you receive the wrong item or a damaged product, please contact us as soon as possible for assistance.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Processing Time</strong><br>Refunds and returns may take a few business days to process depending on the nature of the request.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Contact Us</strong><br>For any return or refund inquiries, please reach out through the contact information provided on our website.</p>\n<!-- /wp:paragraph -->', 'Refund and Returns Policy', '', 'draft', 'closed', 'closed', '', 'refund_returns', '', '', '2026-03-30 01:12:24', '2026-03-30 01:12:24', '', 0, 'http://localhost/bookshop/?page_id=13', 0, 'page', '', 0),
