(21, 1, '2026-03-29 23:13:37', '2026-03-29 23:13:37', '<p data-start=\"235\" data-end=\"299\"><strong data-start=\"235\" data-end=\"299\">A modern love story that feels real, raw, and unforgettable.</strong></p>\r\n<p data-start=\"301\" data-end=\"534\"><em data-start=\"301\" data-end=\"316\">Normal People</em> by <span class=\"hover:entity-accent entity-underline inline cursor-pointer align-baseline\"><span class=\"whitespace-normal\">Sally Rooney</span></span> follows Connell and Marianne—two teenagers from the same small town whose lives become deeply intertwined as they navigate school, university, and the messy space in between.</p>\r\n<p data-start=\"536\" data-end=\"729\">Despite their strong connection, differences in background, status, and communication pull them apart again and again. What unfolds is an intimate story of love, identity, and emotional growth.</p>\r\n\r\n\r\n[caption id=\"attachment_23\" align=\"alignnone\" width=\"320\"]<img class=\" wp-image-23\" src=\"http://localhost/bookshop/wp-content/uploads/2026/03/book.webp\" alt=\"\" width=\"320\" height=\"427\" /> Version 2 of the cover[/caption]\r\n\r\n<hr data-start=\"731\" data-end=\"734\" />\r\n\r\n<h3 data-section-id=\"1mdoose\" data-start=\"736\" data-end=\"754\">✨ Key Features</h3>\r\n<ul data-start=\"755\" data-end=\"1015\">\r\n 	<li data-section-id=\"1943vfs\" data-start=\"755\" data-end=\"809\">A <strong data-start=\"759\" data-end=\"787\">character-driven romance</strong> grounded in realism</li>\r\n 	<li data-section-id=\"1tz09k8\" data-start=\"810\" data-end=\"873\">Explores <strong data-start=\"821\" data-end=\"871\">relationships, mental health, and social class</strong></li>\r\n 	<li data-section-id=\"1uaslim\" data-start=\"874\" data-end=\"948\">Written in a <strong data-start=\"889\" data-end=\"915\">clean, immersive style</strong> that feels personal and direct</li>\r\n 	<li data-section-id=\"19x2358\" data-start=\"949\" data-end=\"1015\">International bestseller with a widely acclaimed TV adaptation</li>\r\n</ul>\r\n\r\n<hr data-start=\"1017\" data-end=\"1020\" />\r\n\r\n<h3 data-section-id=\"1tetnml\" data-start=\"1022\" data-end=\"1040\">🎯 Perfect for</h3>\r\n<p data-start=\"1041\" data-end=\"1149\">Readers who enjoy <strong data-start=\"1059\" data-end=\"1099\">emotional, thought-provoking stories</strong> and realistic portrayals of modern relationships.</p>\r\n\r\n\r\n<hr data-start=\"1151\" data-end=\"1154\" />\r\n\r\n<h3 data-section-id=\"ooj8ta\" data-start=\"1156\" data-end=\"1195\">📦 Product Details (example format)</h3>\r\n<ul data-start=\"1196\" data-end=\"1318\">\r\n 	<li data-section-id=\"1cmnpho\" data-start=\"1196\" data-end=\"1220\">Author: Sally Rooney</li>\r\n 	<li data-section-id=\"18qmsuu\" data-start=\"1221\" data-end=\"1262\">Genre: Contemporary Fiction / Romance</li>\r\n 	<li data-section-id=\"fh1ks1\" data-start=\"1263\" data-end=\"1296\">Format: Paperback / Hardcover</li>\r\n 	<li data-section-id=\"1lp14du\" data-start=\"1297\" data-end=\"1318\">Language: English</li>\r\n</ul>', 'Normal people', '', 'publish', 'open', 'closed', '', 'normal-people', '', '', '2026-03-29 23:25:28', '2026-03-29 23:25:28', '', 0, 'http://localhost/bookshop/?post_type=product&#038;p=21', 0, 'product', '', 0),
