(27, 1, '2026-03-29 23:43:15', '2026-03-29 23:43:15', '<p data-start=\"219\" data-end=\"289\"><strong data-start=\"219\" data-end=\"289\">An epic tale of ambition, power, and survival in medieval England.</strong></p>\r\n<p data-start=\"291\" data-end=\"504\"><em data-start=\"291\" data-end=\"317\">The Pillars of the Earth</em> by <span class=\"hover:entity-accent entity-underline inline cursor-pointer align-baseline\"><span class=\"whitespace-normal\">Ken Follett</span></span> is a sweeping historical novel set in the 12th century, centered around the building of a grand cathedral in the fictional town of Kingsbridge.</p>\r\n<p data-start=\"506\" data-end=\"690\">As war, political intrigue, and shifting loyalties shape the land, the lives of builders, nobles, and clergy become deeply intertwined—each driven by ambition, love, revenge, or faith.</p>\r\n\r\n\r\n<hr data-start=\"692\" data-end=\"695\" />\r\n\r\n<h3 data-section-id=\"1mdoose\" data-start=\"697\" data-end=\"715\">✨ Key Features</h3>\r\n<ul data-start=\"716\" data-end=\"909\">\r\n 	<li data-section-id=\"149w3hr\" data-start=\"716\" data-end=\"758\">Rich, immersive <strong data-start=\"734\" data-end=\"756\">historical fiction</strong></li>\r\n 	<li data-section-id=\"6g4ygo\" data-start=\"759\" data-end=\"809\">Deeply developed <strong data-start=\"778\" data-end=\"807\">interconnected characters</strong></li>\r\n 	<li data-section-id=\"bfasor\" data-start=\"810\" data-end=\"856\">Explores <strong data-start=\"821\" data-end=\"854\">power, religion, and survival</strong></li>\r\n 	<li data-section-id=\"1nxsf7p\" data-start=\"857\" data-end=\"909\">Long, detailed storytelling with cinematic scale</li>\r\n</ul>\r\n\r\n<hr data-start=\"911\" data-end=\"914\" />\r\n\r\n<h3 data-section-id=\"1tetnml\" data-start=\"916\" data-end=\"934\">🎯 Perfect for</h3>\r\n<ul data-start=\"935\" data-end=\"1090\">\r\n 	<li data-section-id=\"1atqu96\" data-start=\"935\" data-end=\"997\">Fans of <strong data-start=\"945\" data-end=\"979\">Game of Thrones–style politics</strong> (but realistic)</li>\r\n 	<li data-section-id=\"155domd\" data-start=\"998\" data-end=\"1046\">Readers who enjoy <strong data-start=\"1018\" data-end=\"1044\">long, immersive novels</strong></li>\r\n 	<li data-section-id=\"j4nc9z\" data-start=\"1047\" data-end=\"1090\">Lovers of history and medieval settings</li>\r\n</ul>\r\n\r\n<hr data-start=\"1092\" data-end=\"1095\" />\r\n\r\n<h3 data-section-id=\"1c1hc5w\" data-start=\"1097\" data-end=\"1119\">📦 Product Details</h3>\r\n<ul data-start=\"1120\" data-end=\"1271\">\r\n 	<li data-section-id=\"9fm2ob\" data-start=\"1120\" data-end=\"1143\">Author: Ken Follett</li>\r\n 	<li data-section-id=\"1nsd2hd\" data-start=\"1144\" data-end=\"1181\">Genre: Historical Fiction / Drama</li>\r\n 	<li data-section-id=\"1o5253z\" data-start=\"1182\" data-end=\"1215\">Setting: 12th-century England</li>\r\n 	<li data-section-id=\"fh1ks1\" data-start=\"1216\" data-end=\"1249\">Format: Paperback / Hardcover</li>\r\n 	<li data-section-id=\"1lp14du\" data-start=\"1250\" data-end=\"1271\">Language: English</li>\r\n</ul>', 'World without End', '', 'publish', 'open', 'closed', '', 'world-without-end', '', '', '2026-03-29 23:43:45', '2026-03-29 23:43:45', '', 0, 'http://localhost/bookshop/?post_type=product&#038;p=27', 0, 'product', '', 0),
