(30, 1, '2026-03-29 23:57:43', '2026-03-29 23:57:43', '<p data-start=\"227\" data-end=\"299\"><strong data-start=\"227\" data-end=\"299\">A heartfelt coming-of-age story set on the infamous Alcatraz Island.</strong></p>\r\n<p data-start=\"301\" data-end=\"483\"><em data-start=\"301\" data-end=\"327\">Al Capone Does My Shirts</em> by <span class=\"hover:entity-accent entity-underline inline cursor-pointer align-baseline\"><span class=\"whitespace-normal\">Gennifer Choldenko</span></span> follows Moose Flanagan, a young boy who moves to Alcatraz in 1935 when his father takes a job as a prison guard.</p>\r\n<p data-start=\"485\" data-end=\"714\">While adjusting to life on the island—home to some of America’s most dangerous criminals, including Al Capone—Moose also navigates family struggles, friendships, and the responsibility of caring for his sister with special needs.</p>\r\n\r\n\r\n<hr data-start=\"716\" data-end=\"719\" />\r\n\r\n<h3 data-section-id=\"1mdoose\" data-start=\"721\" data-end=\"739\">✨ Key Features</h3>\r\n<ul data-start=\"740\" data-end=\"934\">\r\n 	<li data-section-id=\"6sdi86\" data-start=\"740\" data-end=\"794\">Unique setting: <strong data-start=\"758\" data-end=\"792\">life on Alcatraz prison island</strong></li>\r\n 	<li data-section-id=\"1gs53fm\" data-start=\"795\" data-end=\"845\">Mix of <strong data-start=\"804\" data-end=\"843\">humor, history, and emotional depth</strong></li>\r\n 	<li data-section-id=\"nq1a0k\" data-start=\"846\" data-end=\"889\">Strong <strong data-start=\"855\" data-end=\"887\">family and friendship themes</strong></li>\r\n 	<li data-section-id=\"1fsrsva\" data-start=\"890\" data-end=\"934\">Easy-to-read but meaningful storytelling</li>\r\n</ul>\r\n\r\n<hr data-start=\"936\" data-end=\"939\" />\r\n\r\n<h3 data-section-id=\"1tetnml\" data-start=\"941\" data-end=\"959\">🎯 Perfect for</h3>\r\n<ul data-start=\"960\" data-end=\"1090\">\r\n 	<li data-section-id=\"1m1u0au\" data-start=\"960\" data-end=\"993\">Middle school to teen readers</li>\r\n 	<li data-section-id=\"is963t\" data-start=\"994\" data-end=\"1042\">Fans of <strong data-start=\"1004\" data-end=\"1040\">historical coming-of-age stories</strong></li>\r\n 	<li data-section-id=\"1vcokvn\" data-start=\"1043\" data-end=\"1090\">Readers who enjoy emotional but light reads</li>\r\n</ul>\r\n\r\n<hr data-start=\"1092\" data-end=\"1095\" />\r\n\r\n<h3 data-section-id=\"1c1hc5w\" data-start=\"1097\" data-end=\"1119\">📦 Product Details</h3>\r\n<ul data-start=\"1120\" data-end=\"1288\">\r\n 	<li data-section-id=\"16udc3i\" data-start=\"1120\" data-end=\"1150\">Author: Gennifer Choldenko</li>\r\n 	<li data-section-id=\"zyf5j5\" data-start=\"1151\" data-end=\"1196\">Genre: Historical Fiction / Coming-of-Age</li>\r\n 	<li data-section-id=\"u8pudb\" data-start=\"1197\" data-end=\"1232\">Setting: 1930s, Alcatraz Island</li>\r\n 	<li data-section-id=\"fh1ks1\" data-start=\"1233\" data-end=\"1266\">Format: Paperback / Hardcover</li>\r\n 	<li data-section-id=\"1lp14du\" data-start=\"1267\" data-end=\"1288\">Language: English</li>\r\n</ul>', 'Al Capone does my shirts', '', 'publish', 'open', 'closed', '', 'al-capone-does-my-shirts', '', '', '2026-03-31 11:05:04', '2026-03-31 11:05:04', '', 0, 'http://localhost/bookshop/?post_type=product&#038;p=30', 0, 'product', '', 0),
