(47, 1, '2026-03-30 00:47:26', '2026-03-30 00:47:26', '<!-- wp:template-part {\"slug\":\"header\",\"theme\":\"twentytwentyfive\"} /-->\n\n<!-- wp:group {\"tagName\":\"main\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"var:preset|spacing|60\"}}},\"layout\":{\"type\":\"constrained\"}} -->\n<main class=\"wp-block-group\" style=\"margin-top:var(--wp--preset--spacing--60)\"><!-- wp:heading {\"textAlign\":\"left\",\"level\":1,\"className\":\"is-style-default\",\"fontSize\":\"x-large\"} -->\n<h1 class=\"wp-block-heading has-text-align-left is-style-default has-x-large-font-size\"><strong>The Kabarak Bookshop</strong></h1>\n<!-- /wp:heading -->\n\n<!-- wp:group {\"align\":\"full\",\"style\":{\"spacing\":{\"margin\":{\"top\":\"0\",\"bottom\":\"0\"}}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group alignfull\" style=\"margin-top:0;margin-bottom:0\"><!-- wp:columns {\"align\":\"full\",\"style\":{\"spacing\":{\"blockGap\":{\"left\":\"0\"}}}} -->\n<div class=\"wp-block-columns alignfull\"><!-- wp:column {\"width\":\"55%\",\"className\":\"is-style-section-1\"} -->\n<div class=\"wp-block-column is-style-section-1\" style=\"flex-basis:55%\"><!-- wp:cover {\"url\":\"http://localhost/bookshop/wp-content/uploads/2026/03/ChatGPT-Image-Mar-30-2026-03_25_22-AM.png\",\"id\":42,\"dimRatio\":0,\"customOverlayColor\":\"#f7f7f7\",\"isUserOverlayColor\":false,\"isDark\":false,\"sizeSlug\":\"full\",\"style\":{\"dimensions\":{\"aspectRatio\":\"1\"}},\"layout\":{\"type\":\"default\"}} -->\n<div class=\"wp-block-cover is-light\"><img class=\"wp-block-cover__image-background wp-image-42 size-full\" alt=\"\" src=\"http://localhost/bookshop/wp-content/uploads/2026/03/ChatGPT-Image-Mar-30-2026-03_25_22-AM.png\" data-object-fit=\"cover\"/><span aria-hidden=\"true\" class=\"wp-block-cover__background has-background-dim-0 has-background-dim\" style=\"background-color:#f7f7f7\"></span><div class=\"wp-block-cover__inner-container\"><!-- wp:spacer {\"height\":\"var:preset|spacing|2