wp-block-group\" style=\"padding-right:0;padding-left:0\"><!-- wp:navigation {\"ref\":54,\"overlayMenu\":\"never\",\"style\":{\"spacing\":{\"blockGap\":\"var:preset|spacing|20\"}},\"fontSize\":\"medium\",\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\"},\"ariaLabel\":\"Featured\"} /--></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->\n\n<!-- wp:spacer {\"height\":\"var:preset|spacing|60\"} -->\n<div style=\"height:var(--wp--preset--spacing--60)\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n<!-- /wp:spacer -->\n\n<!-- wp:group {\"align\":\"full\",\"layout\":{\"type\":\"flex\",\"flexWrap\":\"wrap\",\"justifyContent\":\"space-between\"}} -->\n<div class=\"wp-block-group alignfull\"><!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">Twenty Twenty-Five</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"small\"} -->\n<p class=\"has-small-font-size\">\n			Designed with <a href=\"https://wordpress.org\" rel=\"nofollow\">WordPress</a>			</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group --></div>\n<!-- /wp:group -->', 'Footer', '', 'inherit', 'closed', 'closed', '', '44-revision-v1', '', '', '2026-03-30 01:21:51', '2026-03-30 01:21:51', '', 44, 'http://localhost/bookshop/?p=58', 0, 'revision', '', 0),
