(84, 1, '2026-03-30 23:11:59', '2026-03-30 23:11:59', '<p data-start=\"215\" data-end=\"278\"><strong data-start=\"215\" data-end=\"278\">A dangerous heist. A crew of outcasts. No room for failure.</strong></p>\r\n<p data-start=\"280\" data-end=\"448\"><em data-start=\"280\" data-end=\"294\">Six of Crows</em> by <span class=\"hover:entity-accent entity-underline inline cursor-pointer align-baseline\"><span class=\"whitespace-normal\">Leigh Bardugo</span></span> follows criminal mastermind Kaz Brekker as he assembles a team of six skilled misfits for an impossible heist.</p>\r\n<p data-start=\"450\" data-end=\"606\">Each member has their own past, secrets, and motivations—but if they succeed, they’ll earn a reward beyond their dreams. If they fail… they don’t walk away.</p>\r\n\r\n\r\n<hr data-start=\"608\" data-end=\"611\" />\r\n\r\n<h3 data-section-id=\"1mdoose\" data-start=\"613\" data-end=\"631\">✨ Key Features</h3>\r\n<ul data-start=\"632\" data-end=\"804\">\r\n 	<li data-section-id=\"qlzahb\" data-start=\"632\" data-end=\"675\">Dark fantasy with a <strong data-start=\"654\" data-end=\"673\">heist storyline</strong></li>\r\n 	<li data-section-id=\"epwtvh\" data-start=\"676\" data-end=\"722\">Strong, memorable <strong data-start=\"696\" data-end=\"720\">multi-character cast</strong></li>\r\n 	<li data-section-id=\"eeuiyl\" data-start=\"723\" data-end=\"764\">Twists, strategy, and emotional depth</li>\r\n 	<li data-section-id=\"15l9mq0\" data-start=\"765\" data-end=\"804\">First book in a bestselling duology</li>\r\n</ul>\r\n\r\n<hr data-start=\"806\" data-end=\"809\" />\r\n\r\n<h3 data-section-id=\"1tetnml\" data-start=\"811\" data-end=\"829\">🎯 Perfect for</h3>\r\n<ul data-start=\"830\" data-end=\"927\">\r\n 	<li data-section-id=\"10vmfwv\" data-start=\"830\" data-end=\"848\">Fantasy lovers</li>\r\n 	<li data-section-id=\"3b63i5\" data-start=\"849\" data-end=\"894\">Fans of <em data-start=\"859\" data-end=\"892\">smart, character-driven stories</em></li>\r\n 	<li data-section-id=\"mye5gt\" data-start=\"895\" data-end=\"927\">Teen and young adult readers</li>\r\n</ul>\r\n\r\n<hr data-start=\"929\" data-end=\"932\" />\r\n\r\n<h3 data-section-id=\"1c1hc5w\" data-start=\"934\" data-end=\"956\">📦 Product Details</h3>\r\n<ul data-start=\"957\" data-end=\"1069\">\r\n 	<li data-section-id=\"7aeu4g\" data-start=\"957\" data-end=\"982\">Author: Leigh Bardugo</li>\r\n 	<li data-section-id=\"lj845a\" data-start=\"983\" data-end=\"1013\">Genre: Fantasy / Adventure</li>\r\n 	<li data-section-id=\"fh1ks1\" data-start=\"1014\" data-end=\"1047\">Format: Paperback / Hardcover</li>\r\n 	<li data-section-id=\"1lp14du\" data-start=\"1048\" data-end=\"1069\">Language: English</li>\r\n</ul>', 'Six of Crows', '', 'publish', 'open', 'closed', '', 'six-of-crows', '', '', '2026-03-30 23:11:59', '2026-03-30 23:11:59', '', 0, 'http://localhost/bookshop/?post_type=product&#038;p=84', 0, 'product', '', 0),
