(96, 1, '2026-03-30 23:30:18', '2026-03-30 23:30:18', '<p data-start=\"2580\" data-end=\"2628\"><strong data-start=\"2580\" data-end=\"2628\">Change how you think about money and wealth.</strong></p>\r\n<p data-start=\"2630\" data-end=\"2832\"><em data-start=\"2630\" data-end=\"2649\">Rich Dad Poor Dad</em> by <span class=\"hover:entity-accent entity-underline inline cursor-pointer align-baseline\"><span class=\"whitespace-normal\">Robert Kiyosaki</span></span> compares two different mindsets about money—one focused on working for income, and the other on building assets and financial independence.</p>\r\n<p data-start=\"2834\" data-end=\"2929\">It introduces simple but powerful ideas about investing, saving, and creating long-term wealth.</p>\r\n\r\n\r\n<hr data-start=\"2931\" data-end=\"2934\" />\r\n\r\n<h3 data-section-id=\"1mdoose\" data-start=\"2936\" data-end=\"2954\">✨ Key Features</h3>\r\n<ul data-start=\"2955\" data-end=\"3110\">\r\n 	<li data-section-id=\"2exm3v\" data-start=\"2955\" data-end=\"2999\">Easy-to-understand <strong data-start=\"2976\" data-end=\"2997\">financial lessons</strong></li>\r\n 	<li data-section-id=\"1lz46bm\" data-start=\"3000\" data-end=\"3038\">Focus on <strong data-start=\"3011\" data-end=\"3036\">assets vs liabilities</strong></li>\r\n 	<li data-section-id=\"osxq6h\" data-start=\"3039\" data-end=\"3088\">Encourages <strong data-start=\"3052\" data-end=\"3086\">financial independence mindset</strong></li>\r\n 	<li data-section-id=\"1ek8zks\" data-start=\"3089\" data-end=\"3110\">Beginner-friendly</li>\r\n</ul>\r\n\r\n<hr data-start=\"3112\" data-end=\"3115\" />\r\n\r\n<h3 data-section-id=\"1tetnml\" data-start=\"3117\" data-end=\"3135\">🎯 Perfect for</h3>\r\n<ul data-start=\"3136\" data-end=\"3233\">\r\n 	<li data-section-id=\"12lte6g\" data-start=\"3136\" data-end=\"3165\">Students and young adults</li>\r\n 	<li data-section-id=\"129o0oa\" data-start=\"3166\" data-end=\"3190\">Beginners in finance</li>\r\n 	<li data-section-id=\"1ilv4w9\" data-start=\"3191\" data-end=\"3233\">Anyone looking to improve money habits</li>\r\n</ul>', 'Rich Dad Poor Dad', '', 'publish', 'open', 'closed', '', 'rich-dad-poor-dad', '', '', '2026-03-30 23:30:18', '2026-03-30 23:30:18', '', 0, 'http://localhost/bookshop/?post_type=product&#038;p=96', 0, 'product', '', 0),
